insert into public.schools (
  name,
  state,
  city,
  setting,
  student_body,
  affiliation,
  grades,
  enrollment,
  pct_boarding,
  pct_international,
  boarding_tuition_usd,
  acceptance_rate_pct,
  avg_ssat_pctile,
  offers_financial_aid,
  niche_grade,
  strengths,
  website_url,
  niche_profile_url,
  notes
)
select
  name,
  state,
  city,
  setting,
  student_body,
  affiliation,
  grades,
  enrollment,
  pct_boarding,
  pct_international,
  boarding_tuition_usd,
  acceptance_rate_pct,
  avg_ssat_pctile,
  offers_financial_aid,
  niche_grade,
  coalesce(strengths, '{}'),
  website_url,
  niche_profile_url,
  notes
from import_rows
on conflict (natural_key)
do update set
  setting = excluded.setting,
  student_body = excluded.student_body,
  affiliation = excluded.affiliation,
  grades = excluded.grades,
  enrollment = excluded.enrollment,
  pct_boarding = excluded.pct_boarding,
